import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Tests for issue: Starting a line with || causes internal error from ktlint --format
 * https://github.com/pinterest/ktlint/issues/new
 */
internal class IndentationRuleOrOperatorOnNewLineTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given an if-statement with OR operator starting on new line should not crash`() {
        val code =
            """
            package com.my.lint.rules

            import org.jetbrains.kotlin.com.intellij.lang.ASTNode

            class BreakKtlintFormatRule {
                fun test(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
                ) {
                    if (node.text.contains("this")
                        || node.text.contains("that")
                    ) {
                        emit(node.startOffset, "My violation detail", false)
                    }
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a binary expression with OR operator starting on new line should not crash`() {
        val code =
            """
            val foo = true
                || false
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a binary expression with AND operator starting on new line should not crash`() {
        val code =
            """
            val foo = true
                && false
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a dot-qualified expression on new line after OR operator should not crash`() {
        val code =
            """
            val foo = node.text.contains("this")
                || node.text.contains("that")
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an if-statement condition with OR operator and incorrect indentation should fix it`() {
        val code =
            """
            fun foo() {
                if (a
            || b
                ) {
                    println()
                }
            }
            """.trimIndent()
        val formattedCode =
            """
            fun foo() {
                if (a
                    || b
                ) {
                    println()
                }
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .hasLintViolation(3, 1, "Unexpected indentation (0) (should be 8)")
            .isFormattedAs(formattedCode)
    }
}
"}

